### Disable Nginx Buffering for Next.js Streaming Responses

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/self-hosting.mdx

This `next.config.js` snippet configures custom headers to disable Nginx buffering by setting `X-Accel-Buffering` to `no`. This is crucial for enabling streaming responses in the Next.js App Router when self-hosting behind an Nginx proxy, ensuring that content is streamed as it becomes available.

```javascript
module.exports = {
  async headers() {
    return [
      {
        source: '/:path*{/}?',
        headers: [
          {
            key: 'X-Accel-Buffering',
            value: 'no',
          },
        ],
      },
    ]
  },
}
```

--------------------------------

### Nginx Configuration for Next.js Static Exports

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/static-exports.mdx

A sample Nginx server block configuration to serve the 'out' directory generated by a Next.js static export. It handles clean URLs by trying .html extensions and includes a rewrite rule for blog subdirectories when trailingSlash is disabled.

```nginx
server {
  listen 80;
  server_name acme.com;

  root /var/www/out;

  location / {
      try_files $uri $uri.html $uri/ =404;
  }

  # This is necessary when `trailingSlash: false`.
  # You can omit this when `trailingSlash: true`.
  location /blog/ {
      rewrite ^/blog/(.*)$ /blog/$1.html break;
  }

  error_page 404 /404.html;
  location = /404.html {
      internal;
  }
}
```

--------------------------------

### Configure Nginx to Proxy Next.js HMR WebSocket

Source: https://github.com/vercel/next.js/blob/canary/docs/02-pages/02-guides/upgrading/version-12.mdx

This Nginx configuration snippet correctly proxies WebSocket upgrade requests for Next.js Hot Module Replacement (HMR) to the development server. It is essential when using Nginx to proxy requests to a Next.js development environment to ensure HMR functions properly.

```nginx
location /_next/webpack-hmr {
    proxy_pass http://localhost:3000/_next/webpack-hmr;
    proxy_http_version 1.1;
    proxy_set_header Upgrade $http_upgrade;
    proxy_set_header Connection "upgrade";
}
```

--------------------------------

### Enable Standalone Output Mode in Next.js Configuration

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/03-api-reference/05-config/01-next-config-js/output.mdx

Configure Next.js to automatically create a standalone folder with only necessary files for production deployment. This feature uses output file tracing to include select files from node_modules without requiring full dependency installation.

```javascript
module.exports = {
  output: 'standalone',
}
```

### Reverse Proxy

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/self-hosting.mdx

When self-hosting, it's recommended to use a reverse proxy (like nginx) in front of your Next.js server rather than exposing it directly to the internet. A reverse proxy can handle malformed requests, slow connection attacks, payload size limits, rate limiting, and other security concerns, offloading these tasks from the Next.js server. This allows the server to dedicate its resources to rendering rather than request validation.

import type { CatalogBead, BeadState } from "@/types/bead";

/**
 * Convert a catalog bead definition into a runtime BeadState
 * suitable for the 3D physics chain.
 *
 * Mapping rules:
 * - id:          unique instance id (timestamp + random suffix)
 * - catalogBeadId: preserved for round-trip back to catalog
 * - type:        material maps directly to BeadType
 * - radius:      catalog `size` is a diameter-like concept; radius = size × 0.8
 * - color:       carried through as-is
 */
export function catalogBeadToBeadState(catalogBead: CatalogBead): BeadState {
  return {
    id: `bead-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    catalogBeadId: catalogBead.id,
    type: catalogBead.material,
    radius: catalogBead.size * 0.8,
    color: catalogBead.color,
  };
}

export type BeadId = string;
export type BeadType = "wood" | "silicone" | "knit" | "plastic";
export type BeadShape = "sphere" | "disc" | "star" | "heart" | "cylinder";

export interface CatalogBead {
  id: string;
  name: string;
  nameRu: string;
  shape: BeadShape;
  size: number;
  material: BeadType;
  color: string;
  secondaryColor?: string;
}

export interface BeadState {
  id: BeadId;
  type: BeadType;
  radius: number;
  color: string;
  catalogBeadId?: string;
}

export interface ChainConfig {
  anchorPosition: [number, number, number];
  gravity: [number, number, number];
}

export interface ChainState {
  beads: BeadState[];
  config: ChainConfig;
}

/** Wire format for design serialization (JSON → LZ-String → base64url). */
export interface SerializableDesign {
  v: 1;
  p: "pacifier-holder";
  b: string[]; // catalogBeadId strings
}

@import "tailwindcss";

html {
  overflow: hidden;
  touch-action: none;
}

body {
  margin: 0;
  overflow: hidden;
  touch-action: none;
}

.canvas-container {
  touch-action: none;
}

/* R3F/Three.js sets touch-action: auto inline on the <canvas> element.
   !important is needed to override that inline style so the browser
   does not intercept touch events for scroll/zoom on the 3D canvas. */
.canvas-container canvas {
  touch-action: none !important;
}

/* Catalog bead grid: allow vertical pan scrolling inside the catalog panel.
   The global touch-action: none on html/body blocks all scrolling — this
   class overrides it for the catalog's scrollable bead grid. */
.catalog-scroll {
  touch-action: pan-y;
  -webkit-overflow-scrolling: touch;
}

/* Home page: the template gallery needs normal scrolling behaviour.
   The global touch-action: none and overflow: hidden are for the 3D canvas
   editor and must be overridden here. */
.home-page-root {
  overflow: auto;
  touch-action: auto;
  -webkit-overflow-scrolling: touch;
}

.home-page-root::-webkit-scrollbar {
  display: none;
}

/* Admin panel: the admin dashboard needs normal scrolling behaviour.
   The global touch-action: none and overflow: hidden are for the 3D canvas
   editor and must be overridden here. */
.admin-root {
  overflow: auto;
